document.writeln("	    function mrtgCalCleanVariable(string) {");
document.writeln("	        string = string.split(\" \").join(\"\");");
document.writeln("	        string = string.split(\",\").join(\"\");");
document.writeln("	        string = string.split(\"%\").join(\"\");");
document.writeln("	        string = string.split(\"$\").join(\"\");");
document.writeln("	        return string;");
document.writeln("	    }");
document.writeln("");
document.writeln("	    function mrtgCalcleanErrorSpan() {");
document.writeln("	        document.getElementById(\"errmrtgLoanAmount\").innerHTML = \"\";");
document.writeln("	        document.getElementById(\"errmrtgLoanTerm\").innerHTML = \"\";");
document.writeln("	        document.getElementById(\"errmrtgInterestRate\").innerHTML = \"\";");
document.writeln("	    }");
document.writeln("");
document.writeln("	    function mrtgCalCalculateMonthlyPayment() {");
document.writeln("	        mrtgCalcleanErrorSpan();");
document.writeln("	        var loanAmount = mrtgCalCleanVariable(document.getElementById(\"txtmrtgLoanAmount\").value);");
document.writeln("	        var years = mrtgCalCleanVariable(document.getElementById(\"txtmrtgLoanTerm\").value);");
document.writeln("	        var months = parseFloat(years) * 12;");
document.writeln("	        var interestRate = mrtgCalCleanVariable(document.getElementById(\"txtmrtgInterestRate\").value);");
document.writeln("");
document.writeln("	        var boolAmount = mrtgCalValidateMinMax(\"txtmrtgLoanAmount\", \"errmrtgLoanAmount\", 0, 10000000);");
document.writeln("	        var boolTerm = mrtgCalValidateMinMax(\"txtmrtgLoanTerm\", \"errmrtgLoanTerm\", 0.083, 40);");
document.write("if (mrtgCalSetOptions[2] == \"200\") {");
document.write("        if (boolTerm)");
document.write("            document.getElementById(\"mrtgTermErrDiv\").style.display = 'none';");
document.write("        else");
document.write("            document.getElementById(\"mrtgTermErrDiv\").style.display = 'block';");
document.write("    }");
document.write("    else {");
document.write("        document.getElementById(\"mrtgTermErrDiv\").style.display = 'none';");
document.write("    }");
document.writeln("	        var boolRate = mrtgCalValidateInterestRate(\"txtmrtgInterestRate\", \"errmrtgInterestRate\", 0, 99);");
document.writeln("	        if (boolAmount && boolRate && boolTerm) {");
document.writeln("	            var factor = 1;");
document.writeln("	            var rate = parseFloat(interestRate) / 1200;");
document.writeln("	            var interestRatePlusOne = parseFloat(rate) + 1;");
document.writeln("	            for (var i = 0; i < months; i++) {");
document.writeln("	                factor = parseFloat(factor) * parseFloat(interestRatePlusOne);");
document.writeln("	            }");
document.writeln("	            var result = (parseFloat(parseFloat(loanAmount) * parseFloat(factor) * parseFloat(rate)) / (parseFloat(factor) - 1)).toFixed(2);");
document.writeln("	            document.getElementById(\"mrtgCalrate\").innerHTML = mrtgCalCleanVariable(document.getElementById(\"txtmrtgInterestRate\").value);");
document.writeln("	            document.getElementById(\"mrtgCalyear\").innerHTML = mrtgCalCleanVariable(document.getElementById(\"txtmrtgLoanTerm\").value) +\" years\";");
document.writeln("	            document.getElementById(\"mrtgCalamount\").innerHTML = mrtgCalFormatCurrency(mrtgCalCleanVariable(document.getElementById(\"txtmrtgLoanAmount\").value));");
document.writeln("	            document.getElementById(\"mrtgCalmonthlyPayment\").innerHTML = mrtgCalFormatCurrency(result);");
document.writeln("	            document.getElementById(\"mrtgCalresultDiv\").style.display = \"block\";");
document.writeln("	            document.getElementById(\"mrtgCalbtnText\").innerHTML=\"Recalculate\";");
document.writeln("	        }");
document.writeln("	    }");
document.writeln("        function mrtgCalFormatCurrency(num) {");
document.writeln("                num = num.toString().replace(/\$|\,/g, '');");
document.writeln("                if (isNaN(num))");
document.writeln("                    num = \"0\";");
document.writeln("                sign = (num == (num = Math.abs(num)));");
document.writeln("                num = Math.floor(num * 100 + 0.50000000001);");
document.writeln("                cents = num % 100;");
document.writeln("                num = Math.floor(num / 100).toString();");
document.writeln("                if (cents < 10)");
document.writeln("                    cents = \"0\" + cents;");
document.writeln("                for (var i = 0; i < Math.floor((num.length - (1 + i)) / 3); i++)");
document.writeln("                    num = num.substring(0, num.length - (4 * i + 3)) + ',' +");
document.writeln("                num.substring(num.length - (4 * i + 3));");
document.writeln("                return (((sign) ? '' : '-') + '$' + num + '.' + cents);");
document.writeln("         }");
